// src/components/tools/ToolBox.tsx

import React, { useState } from 'react';
import { useMusic } from '../../context/MusicContext';
import { useMetronome } from '../../hooks/useMetronome';
import { useTuner } from '../../hooks/useTuner';

const TUNER_STROYS = ["Standard E", "Drop D", "Drop C", "D Standard", "Half Step Down"];

const ToolBox: React.FC = () => {
  const { bpm, setBpm, isPlaying, togglePlay } = useMusic();
  useMetronome(bpm);
  
  const { isActive: isTunerActive, startTuner, stopTuner, note: tunerNote, cents, frequency } = useTuner();

  // 🔥 Собственные настройки плагина тюнера
  const [referenceA4, setReferenceA4] = useState(440);
  const [selectedStroy, setSelectedStroy] = useState("Standard E");

  const isPerfectPitch = Math.abs(cents) < 5;
  const leds = Array.from({ length: 21 }, (_, i) => i - 10);
  const activeLedIndex = Math.round(cents / 5);

  return (
    <div style={{ background: 'var(--bg-panel)', borderRadius: 'var(--radius)', border: '1px solid var(--border-color)', padding: '24px', display: 'flex', flexDirection: 'column', gap: '20px', flexShrink: 0 }}>
      
      <div style={{ fontSize: '11px', color: 'var(--text-muted)', fontWeight: 800, textTransform: 'uppercase', letterSpacing: '1px' }}>
        🎛️ Control Center
      </div>

      {/* METRONOME SECTION */}
      <div style={{ display: 'flex', alignItems: 'center', gap: '16px', background: 'var(--bg-root)', padding: '12px 16px', borderRadius: '12px', border: '1px solid var(--border-color)' }}>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '2px' }}>
          <span style={{ fontSize: '9px', color: 'var(--text-muted)', fontWeight: 800, letterSpacing: '0.5px' }}>TEMPO</span>
          <span style={{ fontSize: '14px', color: 'var(--text-primary)', fontWeight: 900 }}>BPM</span>
        </div>
        
        <input 
          type="number" value={bpm} onChange={(e) => setBpm(Number(e.target.value))} 
          style={{ width: '70px', background: 'var(--bg-secondary)', border: '1px solid var(--border-color)', borderRadius: '6px', color: 'var(--text-primary)', fontWeight: 900, fontSize: '18px', outline: 'none', textAlign: 'center', padding: '4px 0' }} 
        />
        
        <button 
  onClick={togglePlay} 
  style={{ marginLeft: 'auto', width: '42px', height: '42px', borderRadius: '50%', background: isPlaying ? 'var(--accent)' : 'var(--bg-secondary)', color: isPlaying ? '#000' : 'var(--accent)', border: `2px solid var(--accent)`, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 900, fontSize: '16px', transition: '0.2s', boxShadow: isPlaying ? '0 0 12px var(--accent)' : 'none' }}
>
  {isPlaying ? '■' : '▶'}
</button>

      </div>

      {/* 🔥 ПРОФЕССИОНАЛЬНЫЙ ГРАФИЧЕСКИЙ ТЮНЕР (WAZA / KORG INTERFACE) */}
      <div style={{ background: '#090a0e', padding: '20px 16px', borderRadius: '12px', border: '2px solid #161922', display: 'flex', flexDirection: 'column', gap: '16px', position: 'relative', boxShadow: 'inset 0 4px 20px rgba(0,0,0,0.9)' }}>
        
        {/* Панель настроек прибора (Верхний тумблер) */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: '8px', borderBottom: '1px solid #1f2330', paddingBottom: '12px' }}>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '2px' }}>
            <span style={{ fontSize: '8px', color: '#555', fontWeight: 900 }}>CALIBRATION</span>
            <select 
              value={referenceA4} 
              onChange={e => setReferenceA4(Number(e.target.value))}
              style={{ background: '#161922', color: '#aaa', border: '1px solid #2d3345', fontSize: '11px', fontWeight: 800, padding: '2px 4px', borderRadius: '4px', outline: 'none', cursor: 'pointer' }}
            >
              {[432, 436, 438, 440, 442, 444, 446].map(hz => <option key={leds.toString() + hz} value={hz}>{hz}Hz</option>)}
            </select>
          </div>

          <div style={{ display: 'flex', flexDirection: 'column', gap: '2px', alignItems: 'flex-end' }}>
            <span style={{ fontSize: '8px', color: '#555', fontWeight: 900 }}>GUITAR TUNING</span>
            <select 
              value={selectedStroy} 
              onChange={e => setSelectedStroy(e.target.value)}
              style={{ background: '#161922', color: '#aaa', border: '1px solid #2d3345', fontSize: '11px', fontWeight: 800, padding: '2px 4px', borderRadius: '4px', outline: 'none', cursor: 'pointer' }}
            >
              {TUNER_STROYS.map(stroy => <option key={stroy} value={stroy}>{stroy}</option>)}
            </select>
          </div>
        </div>

        {/* Экран дисплея (Детектор нот) */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', minHeight: '54px', background: '#020305', borderRadius: '8px', padding: '0 16px', border: '1px solid #12151c' }}>
          <div style={{ display: 'flex', flexDirection: 'column' }}>
            <span style={{ fontSize: '8px', color: isTunerActive ? 'var(--accent)' : '#333', fontWeight: 900, letterSpacing: '0.5px' }}>CHROMATIC</span>
            <span style={{ fontSize: '20px', fontWeight: 900, color: isTunerActive ? '#fff' : '#222', fontFamily: 'monospace' }}>
              {isTunerActive ? (tunerNote || '--') : 'OFF'}
            </span>
          </div>

          {/* Главная кнопка питания педали */}
          <button 
            onClick={isTunerActive ? stopTuner : startTuner}
            style={{
              background: isTunerActive ? 'var(--accent)' : '#161922',
              color: isTunerActive ? '#000' : '#888',
              border: 'none', padding: '8px 16px', borderRadius: '6px', fontSize: '11px', fontWeight: 900, cursor: 'pointer', transition: '0.2s',
              boxShadow: isTunerActive ? '0 0 12px var(--accent)' : 'none'
            }}
          >
            {isTunerActive ? 'BYPASS' : 'TUNER'}
          </button>
        </div>

        {/* Шкала светодиодного стробоскопа (LED Array) */}
        {isTunerActive && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end', height: '18px', padding: '0 4px' }}>
              {leds.map(led => {
                const isCenter = led === 0;
                const isActive = tunerNote && led === activeLedIndex;
                
                let ledBg = '#161922';
                let ledShadow = 'none';

                if (isActive) {
                  if (isCenter) {
                    ledBg = 'var(--accent)';
                    ledShadow = '0 0 10px var(--accent), 0 0 20px var(--accent)';
                  } else {
                    ledBg = '#ff3b30'; // Красные диоды для погрешностей строя
                    ledShadow = '0 0 8px #ff3b30';
                  }
                } else if (isCenter) {
                  ledBg = 'rgba(0, 255, 157, 0.15)'; 
                }

                return (
                  <div key={led.toString() + '-led'} style={{
                    width: isCenter ? '5px' : '3px',
                    height: isCenter ? '18px' : (Math.abs(led) % 5 === 0 ? '12px' : '6px'),
                    background: ledBg,
                    borderRadius: '1px',
                    boxShadow: ledShadow,
                    transition: 'all 0.05s ease-out'
                  }} />
                );
              })}
            </div>

            {/* Метрика частоты струны */}
            <div style={{ display: 'flex', justifyContent: 'space-between', color: '#444', fontSize: '9px', fontWeight: 900, fontFamily: 'monospace', padding: '0 4px' }}>
              <span>b FLAT</span>
              <span style={{ color: isPerfectPitch ? 'var(--accent)' : '#aaa' }}>
                {tunerNote ? `${frequency} Hz | ${cents > 0 ? '+' : ''}${cents}¢` : 'SIGNAL SEARCH...'}
              </span>
              <span># SHARP</span>
            </div>
          </div>
        )}
      </div>

    </div>
  );
};

export default ToolBox;